<# .SYNOPSIS     Foreign Trade Prospecting Skill — One-Click Installer (Windows PowerShell) .DESCRIPTION     Checks all dependencies and sets up the full environment for the skill.     Run: powershell -ExecutionPolicy Bypass -File install.ps1 #>  param(     [string]$SnovioClientId,     [string]$SnovioClientSecret )  $ErrorActionPreference = "Stop" $SkillDir = Split-Path -Parent $PSScriptRoot  Write-Host "" Write-Host "========================================" -ForegroundColor Cyan Write-Host "  Foreign Trade Prospecting Installer" -ForegroundColor Cyan Write-Host "  v2.0 — Windows PowerShell" -ForegroundColor Cyan Write-Host "========================================" -ForegroundColor Cyan Write-Host "" Write-Host "[INFO] Skill directory: $SkillDir" -ForegroundColor Cyan  # ====== Step 1: Check Node.js ====== Write-Host "[1/7] Checking Node.js..." -ForegroundColor White try {     $nodeVer = (node --version 2>&1).TrimStart('v')     $nodeMajor = [int]($nodeVer.Split('.')[0])     if ($nodeMajor -lt 18) {         Write-Host "[ERR] Node.js v$nodeVer is too old. Need >=18." -ForegroundColor Red         Write-Host "[ERR] Download: https://nodejs.org/" -ForegroundColor Red         exit 1     }     Write-Host "[OK] Node.js $($nodeVer)" -ForegroundColor Green } catch {     Write-Host "[ERR] Node.js not found. Install: https://nodejs.org/" -ForegroundColor Red     exit 1 }  # ====== Step 2: Check Python ====== Write-Host "[2/7] Checking Python..." -ForegroundColor White $PythonPath = $null try {     $pyVer = (python --version 2>&1)     if ($pyVer -match "3\.\d+") {         $PythonPath = "python"         Write-Host "[OK] Python: $pyVer" -ForegroundColor Green     } } catch {     try {         $pyVer = (python3 --version 2>&1)         if ($pyVer -match "3\.\d+") {             $PythonPath = "python3"             Write-Host "[OK] Python3: $pyVer" -ForegroundColor Green         }     } catch {         Write-Host "[WARN] Python 3 not found. Config generation will be skipped." -ForegroundColor Yellow         Write-Host "[WARN] Install: https://python.org/downloads/" -ForegroundColor Yellow     } }  # ====== Step 3: Check Docker ====== Write-Host "[3/7] Checking Docker..." -ForegroundColor White try {     $dockerVer = (docker --version 2>&1)     Write-Host "[OK] Docker: $dockerVer" -ForegroundColor Green          # Check if Reacher is running     $reacherRunning = docker ps --format '{{.Names}}' 2>&1 | Select-String 'reacher'     if ($reacherRunning) {         Write-Host "[INFO] Reacher already running. Restarting..." -ForegroundColor Cyan         docker rm -f reacher 2>$null     }          Write-Host "[INFO] Pulling reacherhq/backend:latest..." -ForegroundColor Cyan     docker pull reacherhq/backend:latest 2>&1 | Select-Object -Last 1          docker run -d --name reacher -p 8080:8080 --restart unless-stopped reacherhq/backend:latest 2>$null          Start-Sleep -Seconds 2     try {         $health = Invoke-RestMethod -Uri "http://localhost:8080/health" -TimeoutSec 5         Write-Host "[OK] Reacher running on http://localhost:8080" -ForegroundColor Green     } catch {         Write-Host "[WARN] Reacher may not have started. Check: docker logs reacher" -ForegroundColor Yellow     } } catch {     Write-Host "[WARN] Docker not found. Email verification via Docker will be unavailable." -ForegroundColor Yellow     Write-Host "[WARN] Install Docker Desktop: https://docs.docker.com/desktop/install/windows-install/" -ForegroundColor Yellow }  # ====== Step 4: Install Prospector MCP ====== Write-Host "[4/7] Installing Prospector MCP (free: 50/day)..." -ForegroundColor White try {     npm install -g prospector-mcp 2>&1 | Select-Object -Last 1     Write-Host "[OK] Prospector MCP installed" -ForegroundColor Green } catch {     Write-Host "[WARN] Global install failed. Use: npx prospector-mcp" -ForegroundColor Yellow }  # ====== Step 5: Clone mcp-whatsapp ====== Write-Host "[5/7] Setting up mcp-whatsapp..." -ForegroundColor White $WhatsappDir = "$env:USERPROFILE\mcp-whatsapp" if (Test-Path $WhatsappDir) {     Write-Host "[OK] mcp-whatsapp already exists at $WhatsappDir" -ForegroundColor Green } else {     try {         git clone https://github.com/Sealjay/mcp-whatsapp.git $WhatsappDir 2>&1 | Select-Object -Last 1         Push-Location $WhatsappDir         if (Test-Path "Makefile") {             make build 2>&1 | Select-Object -Last 3         }         Pop-Location         Write-Host "[OK] mcp-whatsapp cloned to $WhatsappDir" -ForegroundColor Green     } catch {         Write-Host "[WARN] Clone failed. Manual setup:" -ForegroundColor Yellow         Write-Host "[WARN]   git clone https://github.com/Sealjay/mcp-whatsapp.git $WhatsappDir" -ForegroundColor Yellow     } }  # ====== Step 6: Generate MCP Config ====== Write-Host "[6/7] Generating MCP config..." -ForegroundColor White if ($PythonPath) {     $genArgs = @("$SkillDir\scripts\generate_config.py")     if ($SnovioClientId) { $genArgs += "--snovio-id"; $genArgs += $SnovioClientId }     if ($SnovioClientSecret) { $genArgs += "--snovio-secret"; $genArgs += $SnovioClientSecret }     try {         & $PythonPath $genArgs         Write-Host "[OK] MCP config generated" -ForegroundColor Green     } catch {         Write-Host "[WARN] Config generation had issues. Run manually:" -ForegroundColor Yellow         Write-Host "[WARN]   python $SkillDir\scripts\generate_config.py" -ForegroundColor Yellow     } } else {     Write-Host "[WARN] Skipped (Python 3 not available)" -ForegroundColor Yellow }  # ====== Step 7: Windows Firewall Check ====== Write-Host "[7/7] Checking Windows Firewall..." -ForegroundColor White try {     $rule = Get-NetFirewallRule -DisplayName "Codex Docker Reacher" -ErrorAction SilentlyContinue     if (-not $rule) {         Write-Host "[INFO] Adding firewall rule for port 8080 (Reacher)..." -ForegroundColor Cyan         New-NetFirewallRule -DisplayName "Codex Docker Reacher" -Direction Inbound -LocalPort 8080 -Protocol TCP -Action Allow 2>$null     }     Write-Host "[OK] Firewall ready" -ForegroundColor Green } catch {     Write-Host "[INFO] Firewall check skipped (not admin or not Windows Defender)" -ForegroundColor Cyan }  # ====== Summary ====== Write-Host "" Write-Host "========================================" -ForegroundColor Cyan Write-Host "  Installation Complete!" -ForegroundColor Cyan Write-Host "========================================" -ForegroundColor Cyan Write-Host "" Write-Host "  Verification checklist:" -ForegroundColor White Write-Host "  [ ] Docker + Reacher:  curl http://localhost:8080/health" -ForegroundColor White Write-Host "  [ ] Prospector:        npx prospector-mcp --help" -ForegroundColor White Write-Host "  [ ] mcp-whatsapp:      dir $env:USERPROFILE\mcp-whatsapp\bin\" -ForegroundColor White Write-Host "  [ ] MCP config:        type $env:USERPROFILE\.codex\mcp.json" -ForegroundColor White Write-Host "" Write-Host "  Next steps:" -ForegroundColor White Write-Host "  1. Start WhatsApp: cd $env:USERPROFILE\mcp-whatsapp; .\bin\whatsapp-mcp serve" -ForegroundColor White Write-Host "  2. Scan QR: open http://127.0.0.1:8765/pair in browser" -ForegroundColor White Write-Host "  3. Snov.io Key: get from https://app.snov.io > Account > API" -ForegroundColor White Write-Host "     Or run: python $SkillDir\scripts\generate_config.py --snovio-id YOUR_ID --snovio-secret YOUR_SECRET" -ForegroundColor White Write-Host "  4. Restart Codex" -ForegroundColor White Write-Host "" Write-Host "  No-MCP mode (direct Python scripts):" -ForegroundColor Cyan Write-Host "  `$env:SNOVIO_CLIENT_ID='xxx'" -ForegroundColor Cyan Write-Host "  `$env:SNOVIO_CLIENT_SECRET='xxx'" -ForegroundColor Cyan Write-Host "  python $SkillDir\scripts\snovio_api.py balance" -ForegroundColor Cyan Write-Host "  python $SkillDir\scripts\verify_email_direct.py test@gmail.com" -ForegroundColor Cyan Write-Host ""